/**
 * @method 
 * @name f_SetDefaultData 
 * @description Default Data Setting
 */
scwin.f_SetDefaultData = function () {
  scwin.f_GetConfirmCntTotAmt(); // 건수/총금액 계산

  ed_wrkDtSt.setValue(scwin.vQryStDt); // 출발일자시작
  ed_wrkDtEnd.setValue(scwin.vQryEndDt); // 출발일자종료
  ed_copCoConfirmDtSt.setValue(scwin.vQryStDt); // 확인일자시작
  ed_copCoConfirmDtEnd.setValue(scwin.vQryEndDt); // 확인일자종료

  acb_copCoConfirmClsCd.setMaxLength(50);
  acb_copCoConfirmClsCd.setSelectedIndex(0);
  acb_pchsAdmitClsCd.setMaxLength(50);
  acb_pchsAdmitClsCd.setSelectedIndex(0);
  acb_wrkImpleKndCd.setSelectedIndex(0);
  if (scwin.userClsCd != "01") {
    // 내부사용자가 아니면
    ed_pchsClntNo.setValue(scwin.loginClntNo);
    txt_pchsClntNm.setValue(scwin.loginClntNm);
    ed_pchsClntNo.setDisabled(true);
    txt_pchsClntNm.setDisabled(true);
    img_PopUp1.setDisabled(true);
  } else {
    ed_pchsClntNo.focus();
  }
  ;
};

/**
 * @method 
 * @name f_RetrieveWorkImplementLoanChargeList 
 * @description 작업도구임차료목록 조회
 */
scwin.f_RetrieveWorkImplementLoanChargeList = async function () {
  // 검색조건 필수 입력 체크, 동일 날짜 포함 여부 체크
  switch (acb_dtCls.getValue()) {
    case '01':
      // 작업일자 기준
      if (!(await $c.gus.cfValidate($p, [ed_pchsClntNo, ed_wrkDtSt, ed_wrkDtEnd]))) {
        return;
      }
      ;
      if (!$c.gus.cfIsAfterDate($p, dma_wrkDt.get('from'), dma_wrkDt.get('to'))) {
        $c.gus.cfAlertMsg($p, "조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
        ed_wrkDtSt.focus();
        return;
      }
      ;
      break;
    case '02':
      // 확인일자 기준
      if (!(await $c.gus.cfValidate($p, [ed_pchsClntNo, ed_copCoConfirmDtSt, ed_copCoConfirmDtEnd]))) {
        return;
      }
      ;
      if (!$c.gus.cfIsAfterDate($p, dma_copCoConfirmDt.get('from'), dma_copCoConfirmDt.get('to'))) {
        $c.gus.cfAlertMsg($p, "조회 시작일자는 종료일자 보다 이전 날짜 이어야 합니다.");
        ed_copCoConfirmDtSt.focus();
        return;
      }
      ;
      break;
    default:
      break;
  }
  ;

  // 모선과 항차 동시 조회 조건 체크
  if (!$c.gus.cfIsNull($p, ed_coshipvsslCd.getValue()) || !$c.gus.cfIsNull($p, ed_coshipPortcnt.getValue())) {
    if ($c.gus.cfIsNull($p, ed_coshipvsslCd.getValue())) {
      $c.gus.cfAlertMsg($p, "모선를 입력하십시오.");
      ed_coshipvsslCd.focus();
      return;
    } else if ($c.gus.cfIsNull($p, ed_coshipPortcnt.getValue())) {
      $c.gus.cfAlertMsg($p, "항차를 입력하십시오.");
      ed_coshipPortcnt.focus();
      return;
    }
    ;
  }
  ;

  // 구분(미확인포함여부/미승인포함여부)- 쿼리문에서 사용
  if (cbx_unconfirmedIncluYn.getValue() == 0 && cbx_unAdmitIncluYn.getValue() == 0) {
    dma_purchaseListQueryConditionDTO.set("incluYn", "N");
  } else {
    dma_purchaseListQueryConditionDTO.set("incluYn", "Y");
  }
  ;
  $c.sbm.execute($p, sbm_purchaseListQueryConditionDTO);
};

/**
 * @method 
 * @name f_Confirm 
 * @description 작업도구 임차료 확인
 */
scwin.f_Confirm = function () {
  // Data 변경 여부 조회
  if (ds_workImplementLoanChargeList.getModifiedIndex().length == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["자료"]);
    return;
  }
  ;

  // 협력업체확인구분(FS261)이 01:미확인, 03:이의신청, 04:이의거부, 05:이의수용
  let rowData = {};
  let rowCnt = ds_workImplementLoanChargeList.getRowCount();
  for (let i = 0; i < rowCnt; i++) {
    rowData = ds_workImplementLoanChargeList.getRowJSON(i);
    if (rowData.chk == "T") {
      if (rowData.copCoConfirmClsCd == "02") {
        $c.gus.cfAlertMsg($p, "이미 확인된 건이 포함되어 있습니다.");
        return;
      }
      ;
    }
    ;
  }
  ;

  // 일괄적용 확인일자
  let allCopCoConfirmDt = ica_allCopCoConfirmDt.getValue();
  if ($c.gus.cfIsNull($p, allCopCoConfirmDt) || allCopCoConfirmDt == "") {
    allCopCoConfirmDt = scwin.vCurDate;
  }
  ;
  for (let i = 0; i < rowCnt; i++) {
    rowData = ds_workImplementLoanChargeList.getRowJSON(i);
    if (rowData.chk == "T") {
      rowData.copCoConfirmClsCd = "02";
      rowData.copCoConfirmClsNm = "확인";
      rowData.copCoConfirmDt = allCopCoConfirmDt; // 일괄적용 확인일자
      rowData.btn = "T";
      rowData.chk = "F";
      ds_workImplementLoanChargeList.setRowJSON(i, rowData, true);
    }
    ;
  }
  ;
};

/**
 * @method 
 * @name f_ConfirmDtUpdate 
 * @description 작업도구 임차료 확인일자 수정
 */
scwin.f_ConfirmDtUpdate = function () {
  // Data 변경 여부 조회
  if (ds_workImplementLoanChargeList.getModifiedIndex().length == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["자료"]);
    return;
  }
  ;

  // 협력업체확인구분(FS261)이 02:확인 이면서 매입승인구분(FS262)이 01:미승인, 03:보류
  let rowData = {};
  let rowCnt = ds_workImplementLoanChargeList.getRowCount();
  for (let i = 0; i < rowCnt; i++) {
    rowData = ds_workImplementLoanChargeList.getRowJSON(i);
    if (rowData.chk == "T") {
      if (rowData.copCoConfirmClsCd != "02") {
        $c.gus.cfAlertMsg($p, "미확인인 건이 포함되어 있습니다.");
        return;
      }
      ;
      if (rowData.pchsAdmitClsCd == "02") {
        $c.gus.cfAlertMsg($p, "이미 동부 승인이 이루어진 건이 포함되어 있습니다.");
        return;
      }
      ;
    }
  }

  // 일괄적용 확인일자
  let allCopCoConfirmDt = ica_allCopCoConfirmDt.getValue();
  if ($c.gus.cfIsNull($p, allCopCoConfirmDt) || allCopCoConfirmDt == "") {
    allCopCoConfirmDt = scwin.vCurDate;
  }
  for (let i = 0; i < rowCnt; i++) {
    rowData = ds_workImplementLoanChargeList.getRowJSON(i);
    if (rowData.chk == "T") {
      rowData.copCoConfirmDt = allCopCoConfirmDt; // 일괄적용 확인일자
      rowData.btn = "T";
      rowData.chk = "F";
      ds_workImplementLoanChargeList.setRowJSON(i, rowData, true);
    }
    ;
  }
  ;
};

